parameters.text:
=Act as an expert SEO strategist specializing in Generative Engine Optimization (GEO) for Google AI Overviews and AI-driven search results.

Page Details:
URL: {{ $json.pageUrl }}
Type: {{ $json.pageType }}
Current Title: {{ $json.pageTitle }}
Target Keyword: {{ $json.targetKeyword }}
Existing Meta: {{ $json.existingMeta }}

Content Snippet:
{{ ($json.pageContent || '').substring(0, 800) }}

Identified GEO Gaps:
{{ $json.geoGapSummary || 'Missing structured answers, low entity coverage, weak schema.' }}

Top Competing Snippets from Google:
{{ $json.competitorSnippets || 'No data available.' }}

Your task:
1. Write an optimized SEO title (60 chars max) that improves AI Overview inclusion chances.
2. Write a concise meta description / AI summary (155 chars max) with direct answer format.
3. Generate a valid JSON-LD schema markup (Article or Product depending on page type) with all recommended fields for AI crawlers.
4. Provide a GEO score (0-100) estimating the page's current AI Overview readiness.

Respond ONLY in this exact JSON format:
{
  "optimizedTitle": "...",
  "optimizedSummary": "...",
  "schemaMarkup": { ... },
  "geoScore": 0,
  "recommendations": "..."
}

parameters.jsCode:
const item = $input.item.json;
let aiOutput = {};
try {
  const raw = item.output || item.response || item.text || '{}';
  const clean = raw.replace(/```json|```/g, '').trim();
  aiOutput = JSON.parse(clean);
} catch (e) {
  aiOutput = {
    optimizedTitle: item.pageTitle || 'Optimized Page Title',
    optimizedSummary: 'AI-optimized summary pending manual review.',
    schemaMarkup: {},
    geoScore: 0,
    recommendations: 'Manual review required.'
  };
}
return {
  json: {
    ...item,
    optimizedTitle: aiOutput.optimizedTitle || '',
    optimizedSummary: aiOutput.optimizedSummary || '',
    schemaMarkup: JSON.stringify(aiOutput.schemaMarkup || {}),
    geoScore: aiOutput.geoScore || 0,
    recommendations: aiOutput.recommendations || '',
    status: 'Optimized',
    processedDate: new Date().toISOString().split('T')[0],
    processedAt: new Date().toISOString()
  }
};
